--- 文件: D:\LLM\memory\agentmemory\src\index.ts (第 447 至 520 行，共 596 行) ---
 447 |   const needsRebuild = bm25Index.size === 0;
 448 | 
 449 |   if (needsRebuild) {
 450 |     // Fire-and-forget. rebuildIndex iterates every observation across
 451 |     // every session and AWAITS an embedding-provider call per record.
 452 |     // On a large corpus + rate-limited embedding endpoint that can
 453 |     // take HOURS; awaiting it here blocks every subsequent boot step
 454 |     // (including startViewerServer below, leaving the viewer port
 455 |     // unbound for the duration). The index lazily fills in over time
 456 |     // and search degrades gracefully — partial coverage > no viewer
 457 |     // for hours. Errors still surface via the inner .catch.
 458 |     void rebuildIndex(kv)
 459 |       .then((indexCount) => {
 460 |         if (indexCount > 0) {
 461 |           bootLog(`Search index rebuilt: ${indexCount} entries`);
 462 |           indexPersistence.scheduleSave();
 463 |         }
 464 |       })
 465 |       .catch((err) => {
 466 |         console.warn(`[agentmemory] Failed to rebuild search index:`, err);
 467 |       });
 468 |   } else {
 469 |     // Backfill memories into BM25 for users upgrading from <0.9.5: prior
 470 |     // versions of mem::remember never indexed memories, so the persisted
 471 |     // BM25 covers observations only and `memory_smart_search` returns
 472 |     // empty for everything saved via memory_save (#257). Walk KV.memories
 473 |     // and add the ones missing from the restored index. Idempotent on
 474 |     // re-runs because SearchIndex.has() short-circuits already-indexed
 475 |     // ids.
 476 |     try {
 477 |       const memories = await kv.list<import("./types.js").Memory>(KV.memories);
 478 |       let backfilled = 0;
 479 |       for (const memory of memories) {
 480 |         if (memory.isLatest === false) continue;
 481 |         if (!memory.title || !memory.content) continue;
 482 |         if (bm25Index.has(memory.id)) continue;
 483 |         bm25Index.add({
 484 |           id: memory.id,
 485 |           sessionId: memory.sessionIds?.[0] ?? "memory",
 486 |           timestamp: memory.createdAt,
 487 |           type: "decision",
 488 |           title: memory.title,
 489 |           facts: [memory.content],
 490 |           narrative: memory.content,
 491 |           concepts: memory.concepts,
 492 |           files: memory.files,
 493 |           importance: memory.strength,
 494 |         });
 495 |         backfilled++;
 496 |       }
 497 |       if (backfilled > 0) {
 498 |         bootLog(
 499 |           `Backfilled ${backfilled} memories into BM25 (legacy gap before #257)`,
 500 |         );
 501 |         indexPersistence.scheduleSave();
 502 |       }
 503 |     } catch (err) {
 504 |       console.warn(
 505 |         `[agentmemory] Failed to backfill memories into BM25:`,
 506 |         err,
 507 |       );
 508 |     }
 509 |   }
 510 | 
 511 |   // Ready / Endpoints lines are emitted via `bootLog` so they're
 512 |   // buffered in quiet mode and printed verbatim under --verbose. The
 513 |   // CLI surfaces a compact summary when it sees the worker reach
 514 |   // ready state.
 515 |   bootLog(
 516 |     `Ready. ${embeddingProvider ? "Triple-stream (BM25+Vector+Graph)" : "BM25+Graph"} search active.`,
 517 |   );
 518 |   bootLog(
 519 |     `REST API: 124 endpoints at http://localhost:${config.restPort}/agentmemory/*`,
 520 |   );
--- 读取完毕 ---

